import * as flatbuffers from 'flatbuffers';
import { User, Familiar, Post, Tag, PostTagEdge } from './graph-db.js'; // Generated by flatc

// ============================================
//  Data Interfaces
// ============================================

export interface UserData {
  id: string;
  type: 'user';
  createdAt: number;
  updatedAt: number;
  fields: {
  name: string;
  age: number;
};
  relationIds: {
  posts: string[];
  familiars: string[];
};
}

export interface FamiliarData {
  id: string;
  type: 'familiar';
  createdAt: number;
  updatedAt: number;
  fields: {
  name: string;
  age: number;
};
  relationIds: {
  user: string;
};
}

export interface PostData {
  id: string;
  type: 'post';
  createdAt: number;
  updatedAt: number;
  fields: {
  title: string;
  content: string;
  published: boolean;
  viewCount: number;
};
  relationIds: {
  tags: string[];
  author: string;
};
}

export interface TagData {
  id: string;
  type: 'tag';
  createdAt: number;
  updatedAt: number;
  fields: {
  name: string;
};
  relationIds: {
  posts: string[];
};
}

export interface PostTagEdgeData {
  id: string;
  type: 'post_tag_edge';
  from: string; // post ID
  to: string;   // tag ID
  createdAt: number;
}

// ============================================
//  Node Serializers
// ============================================

export const serializeNode = {
  user: (data: UserData): Uint8Array => {
    const builder = new flatbuffers.Builder(1024);
    const id = builder.createString(data.id);
    const name = builder.createString(data.fields.name);
    const relationIds_posts = Array.isArray(data.relationIds.posts) ? data.relationIds.posts : [data.relationIds.posts];
    const postsVector = User.createPostsIdsVector(builder, relationIds_posts.map(id => builder.createString(id)));
    const relationIds_familiars = Array.isArray(data.relationIds.familiars) ? data.relationIds.familiars : [data.relationIds.familiars];
    const familiarsVector = User.createFamiliarsIdsVector(builder, relationIds_familiars.map(id => builder.createString(id)));

    User.startUser(builder);
    User.addId(builder, id);
    User.addName(builder, name);
    User.addAge(builder, data.fields.age);
    User.addCreatedAt(builder, BigInt(data.createdAt));
    User.addUpdatedAt(builder, BigInt(data.updatedAt));
    User.addPostsIds(builder, postsVector);
    User.addFamiliarsIds(builder, familiarsVector);
    const root = User.endUser(builder);
    builder.finish(root);
    return builder.asUint8Array();
  },
  familiar: (data: FamiliarData): Uint8Array => {
    const builder = new flatbuffers.Builder(1024);
    const id = builder.createString(data.id);
    const name = builder.createString(data.fields.name);
    const relationIds_user = Array.isArray(data.relationIds.user) ? data.relationIds.user : [data.relationIds.user];
    const userVector = Familiar.createUserIdsVector(builder, relationIds_user.map(id => builder.createString(id)));

    Familiar.startFamiliar(builder);
    Familiar.addId(builder, id);
    Familiar.addName(builder, name);
    Familiar.addAge(builder, data.fields.age);
    Familiar.addCreatedAt(builder, BigInt(data.createdAt));
    Familiar.addUpdatedAt(builder, BigInt(data.updatedAt));
    Familiar.addUserIds(builder, userVector);
    const root = Familiar.endFamiliar(builder);
    builder.finish(root);
    return builder.asUint8Array();
  },
  post: (data: PostData): Uint8Array => {
    const builder = new flatbuffers.Builder(1024);
    const id = builder.createString(data.id);
    const title = builder.createString(data.fields.title);
    const content = builder.createString(data.fields.content);
    const relationIds_tags = Array.isArray(data.relationIds.tags) ? data.relationIds.tags : [data.relationIds.tags];
    const tagsVector = Post.createTagsIdsVector(builder, relationIds_tags.map(id => builder.createString(id)));
    const relationIds_author = Array.isArray(data.relationIds.author) ? data.relationIds.author : [data.relationIds.author];
    const authorVector = Post.createAuthorIdsVector(builder, relationIds_author.map(id => builder.createString(id)));

    Post.startPost(builder);
    Post.addId(builder, id);
    Post.addTitle(builder, title);
    Post.addContent(builder, content);
    Post.addPublished(builder, data.fields.published);
    Post.addViewCount(builder, data.fields.viewCount);
    Post.addCreatedAt(builder, BigInt(data.createdAt));
    Post.addUpdatedAt(builder, BigInt(data.updatedAt));
    Post.addTagsIds(builder, tagsVector);
    Post.addAuthorIds(builder, authorVector);
    const root = Post.endPost(builder);
    builder.finish(root);
    return builder.asUint8Array();
  },
  tag: (data: TagData): Uint8Array => {
    const builder = new flatbuffers.Builder(1024);
    const id = builder.createString(data.id);
    const name = builder.createString(data.fields.name);
    const relationIds_posts = Array.isArray(data.relationIds.posts) ? data.relationIds.posts : [data.relationIds.posts];
    const postsVector = Tag.createPostsIdsVector(builder, relationIds_posts.map(id => builder.createString(id)));

    Tag.startTag(builder);
    Tag.addId(builder, id);
    Tag.addName(builder, name);
    Tag.addCreatedAt(builder, BigInt(data.createdAt));
    Tag.addUpdatedAt(builder, BigInt(data.updatedAt));
    Tag.addPostsIds(builder, postsVector);
    const root = Tag.endTag(builder);
    builder.finish(root);
    return builder.asUint8Array();
  }
};

// ============================================
//  Node Deserializers
// ============================================

export const deserializeNode = {
  user: (buffer: Uint8Array): UserData => {
    const buf = new flatbuffers.ByteBuffer(buffer);
    const table = User.getRootAsUser(buf);
    
    // Initialize relationIds with defaults for 'many' relations to ensure they are always present.
    const relationIds: any = {
      posts: [],
      familiars: []
    };

    // Check if the vector exists in the buffer and has items
    if (table.postsIdsLength() > 0) {
      const ids = Array.from({ length: table.postsIdsLength() }, (_, i) => table.postsIds(i)!);
      relationIds.posts = ids;
    }
    // Check if the vector exists in the buffer and has items
    if (table.familiarsIdsLength() > 0) {
      const ids = Array.from({ length: table.familiarsIdsLength() }, (_, i) => table.familiarsIds(i)!);
      relationIds.familiars = ids;
    }
    return {
      id: table.id()!,
      type: 'user',
      createdAt: Number(table.createdAt()),
      updatedAt: Number(table.updatedAt()),
      fields: {
      name: table.name()!,
      age: table.age()!
      },
      // Cast to the generated interface to ensure type safety.
      relationIds: relationIds as UserData['relationIds']
    };
  },
  familiar: (buffer: Uint8Array): FamiliarData => {
    const buf = new flatbuffers.ByteBuffer(buffer);
    const table = Familiar.getRootAsFamiliar(buf);
    
    // Initialize relationIds with defaults for 'many' relations to ensure they are always present.
    const relationIds: any = {

    };

    // Check if the vector exists in the buffer and has items
    if (table.userIdsLength() > 0) {
      const ids = Array.from({ length: table.userIdsLength() }, (_, i) => table.userIds(i)!);
      relationIds.user = ids[0];
    }
    return {
      id: table.id()!,
      type: 'familiar',
      createdAt: Number(table.createdAt()),
      updatedAt: Number(table.updatedAt()),
      fields: {
      name: table.name()!,
      age: table.age()!
      },
      // Cast to the generated interface to ensure type safety.
      relationIds: relationIds as FamiliarData['relationIds']
    };
  },
  post: (buffer: Uint8Array): PostData => {
    const buf = new flatbuffers.ByteBuffer(buffer);
    const table = Post.getRootAsPost(buf);
    
    // Initialize relationIds with defaults for 'many' relations to ensure they are always present.
    const relationIds: any = {
      tags: []
    };

    // Check if the vector exists in the buffer and has items
    if (table.tagsIdsLength() > 0) {
      const ids = Array.from({ length: table.tagsIdsLength() }, (_, i) => table.tagsIds(i)!);
      relationIds.tags = ids;
    }
    // Check if the vector exists in the buffer and has items
    if (table.authorIdsLength() > 0) {
      const ids = Array.from({ length: table.authorIdsLength() }, (_, i) => table.authorIds(i)!);
      relationIds.author = ids[0];
    }
    return {
      id: table.id()!,
      type: 'post',
      createdAt: Number(table.createdAt()),
      updatedAt: Number(table.updatedAt()),
      fields: {
      title: table.title()!,
      content: table.content()!,
      published: table.published()!,
      viewCount: table.viewCount()!
      },
      // Cast to the generated interface to ensure type safety.
      relationIds: relationIds as PostData['relationIds']
    };
  },
  tag: (buffer: Uint8Array): TagData => {
    const buf = new flatbuffers.ByteBuffer(buffer);
    const table = Tag.getRootAsTag(buf);
    
    // Initialize relationIds with defaults for 'many' relations to ensure they are always present.
    const relationIds: any = {
      posts: []
    };

    // Check if the vector exists in the buffer and has items
    if (table.postsIdsLength() > 0) {
      const ids = Array.from({ length: table.postsIdsLength() }, (_, i) => table.postsIds(i)!);
      relationIds.posts = ids;
    }
    return {
      id: table.id()!,
      type: 'tag',
      createdAt: Number(table.createdAt()),
      updatedAt: Number(table.updatedAt()),
      fields: {
      name: table.name()!
      },
      // Cast to the generated interface to ensure type safety.
      relationIds: relationIds as TagData['relationIds']
    };
  }
};

// ============================================
//  Edge Serializers
// ============================================

export const serializeEdge = {
  post_tag_edge: (data: PostTagEdgeData): Uint8Array => {
    const builder = new flatbuffers.Builder(256);
    const id = builder.createString(data.id);
    const fromId = builder.createString(data.from);
    const toId = builder.createString(data.to);

    PostTagEdge.startPostTagEdge(builder);
    PostTagEdge.addId(builder, id);
    PostTagEdge.addPostId(builder, fromId);
    PostTagEdge.addTagId(builder, toId);
    PostTagEdge.addCreatedAt(builder, BigInt(data.createdAt));
    const root = PostTagEdge.endPostTagEdge(builder);

    builder.finish(root);
    return builder.asUint8Array();
  }
};

// ============================================
//  Edge Deserializers
// ============================================

export const deserializeEdge = {
  post_tag_edge: (buffer: Uint8Array): PostTagEdgeData => {
    const buf = new flatbuffers.ByteBuffer(buffer);
    const table = PostTagEdge.getRootAsPostTagEdge(buf);
    return {
      id: table.id()!,
      type: 'post_tag_edge',
      from: table.postId()!,
      to: table.tagId()!,
      createdAt: Number(table.createdAt()),
    };
  }
};

// ============================================
//  Supported Type Constants
// ============================================

export const supportedNodeTypes = ['user', 'familiar', 'post', 'tag'] as const;
export const supportedEdgeTypes = ['post_tag_edge'] as const;
